// /frontend/src/components/SearchSection.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";

const FAVORITES_KEY = "wx:favorites";

export default function SearchSection({ value = "", open, onToggle, onSelected }) {
  const [q, setQ] = useState(value);
  const [favorites, setFavorites] = useState([]);
  const boxRef = useRef(null);

  useEffect(() => {
    try {
      const raw = localStorage.getItem(FAVORITES_KEY);
      setFavorites(raw ? JSON.parse(raw) : []);
    } catch {}
  }, []);

  const addFav = () => {
    if (!q.trim()) return;
    const next = Array.from(new Set([q.trim(), ...favorites])).slice(0, 8);
    setFavorites(next);
    localStorage.setItem(FAVORITES_KEY, JSON.stringify(next));
  };

  const filtered = useMemo(() => {
    if (!q.trim()) return favorites;
    return favorites.filter((f) => f.toLowerCase().includes(q.toLowerCase()));
  }, [q, favorites]);

  // Collapse when clicking outside
  useEffect(() => {
    const onDoc = (e) => {
      if (!boxRef.current) return;
      if (!boxRef.current.contains(e.target)) onToggle?.(false);
    };
    if (open) document.addEventListener("mousedown", onDoc);
    return () => document.removeEventListener("mousedown", onDoc);
  }, [open, onToggle]);

  return (
    <div
      ref={boxRef}
      className={`transition-all ${open ? "max-h-96" : "max-h-12"} overflow-hidden`}
    >
      <div className="flex items-center gap-2 rounded-full backdrop-blur-xl bg-black/40 ring-1 ring-white/10 px-3 py-2">
        <button
          onClick={() => onToggle?.(!open)}
          className="text-sm opacity-80 hover:opacity-100"
          title="Toggle search"
        >
          🔎
        </button>
        <input
          className="w-full bg-transparent outline-none placeholder-white/50"
          value={q}
          onChange={(e) => setQ(e.target.value)}
          placeholder="Search city"
          onFocus={() => onToggle?.(true)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && q.trim()) {
              onSelected?.(q.trim());
              onToggle?.(false);
            }
          }}
        />
        <button onClick={addFav} className="text-xs px-2 py-1 rounded-full bg-white/10">
          ☆
        </button>
      </div>

      {/* Favorites dropdown */}
      {open && (
        <div className="mt-2 rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-2">
          {filtered.length === 0 ? (
            <div className="text-sm opacity-60 px-2 py-1">No favorites yet.</div>
          ) : (
            <ul className="divide-y divide-white/10">
              {filtered.map((f) => (
                <li key={f}>
                  <button
                    className="w-full text-left px-3 py-2 hover:bg-white/5 rounded-lg"
                    onClick={() => {
                      onSelected?.(f);
                      onToggle?.(false);
                    }}
                  >
                    {f}
                  </button>
                </li>
              ))}
            </ul>
          )}
        </div>
      )}
    </div>
  );
}
